import { Module } from '@nestjs/common';
import { TasksModule } from './tasks/tasks.module';
@Module({ imports: [TasksModule] })
export class AppModule {}

import { Module } from '@nestjs/common';
import { TasksService } from './tasks.service';
import { TasksController } from './tasks.controller';
@Module({ controllers: [TasksController], providers: [TasksService] })
export class TasksModule {}

import { Injectable, NotFoundException } from '@nestjs/common';
@Injectable()
export class TasksService {
  private tasks = [];
  private idCounter = 1;
  create(payload: any) {
    const task = { id: this.idCounter++, ...payload };
    this.tasks.push(task);
    return task;
  }
  findAll() { return this.tasks; }
  findOne(id: number) {
    const t = this.tasks.find(x => x.id === id);
    if(!t) throw new NotFoundException();
    return t;
  }
  update(id: number, payload: any) {
    const t = this.findOne(id);
    Object.assign(t, payload);
    return t;
  }
  remove(id: number) {
    this.findOne(id);
    this.tasks = this.tasks.filter(x => x.id !== id);
  }
}

import { Controller, Get, Post, Body, Patch, Param, Delete, ParseIntPipe } from '@nestjs/common';
import { TasksService } from './tasks.service';
@Controller('tasks')
export class TasksController {
  constructor(private readonly tasksService: TasksService) {}
  @Post()
  create(@Body() payload: any) { return this.tasksService.create(payload); }
  @Get()
  findAll() { return this.tasksService.findAll(); }
  @Get(':id')
  findOne(@Param('id', ParseIntPipe) id: number) { return this.tasksService.findOne(id); }
  @Patch(':id')
  update(@Param('id', ParseIntPipe) id: number, @Body() payload: any) { return this.tasksService.update(id, payload); }
  @Delete(':id')
  remove(@Param('id', ParseIntPipe) id: number) { return this.tasksService.remove(id); }
}
